-- OpenResty Lua access control script
local user_permissions = {
  alice = {"GET:/", "POST:/"},
  bob   = {"GET:/", "POST:/api"},
  carol = {"GET:/admin"},
}

function validate_permission(ngx, uri)
  local auth_token = ngx.var.http_authorization or ""
  local username = string.match(auth_token, "^Bearer%s+(.+)$")
  if not username then return nil end

  -- Check for admin access
  if ngx.var.uri:find("/admin", nil, true) then
    return user_permissions[username]["GET:/admin"]
  end

  -- Check for API access
  if ngx.var.uri:find("/api", nil, true) then
    return user_permissions[username]["POST:/api"]
  end

  -- Check for other URI patterns
  local uri_pattern = "^" .. ngx.var.uri .. "$"
  for _, pattern in pairs(user_permissions[username]) do
    if ngx.re.match(uri, pattern) then
      return true
    end
  end
  return nil
end

function access()
  local uri = ngx.var.uri
  if validate_permission(ngx, uri) == false then
    return ngx.exit(403)
  end
end